40	/// Parse optimization pipeline from text
41	static LogicalResult parseTextInto(llvm::StringRef text, OpPassManager &PM,
42	                                   MLIRContext *context) {
43	  if (text.empty())
44	    return success();
45	  // Parsing textual pipeline into an existing (nested) OpPassManager.
46	  // NOTE: because opPM is already nested for cuda_tile::EntryOp, the text
47	  // should NOT include an op anchor.
48	  if (failed(parsePassPipeline(text, PM))) {
49	    emitError(UnknownLoc::get(context)) << "Failed to parse pipeline: " << text;
50	    return failure();
51	  }
52	  return success();
53	}
54	
55	/// Build default optimization pipeline
56	static LogicalResult
57	buildDefaultCudaTilePipeline(OpPassManager &nested,
58	                             const TileIROptimizerOptions &opts) {
59	  // 1) Optional FMA fusion
60	  if (opts.enableFuseFMA)
61	    nested.addPass(createFuseFMAPass());
62	
63	  if (opts.optLevel >= 1) {
64	    // 2) Canonicalize + CSE before further opts
65	    nested.addPass(createCanonicalizerPass());
66	    nested.addPass(createCSEPass());
67	
68	    if (opts.optLevel >= 2) {
69	      nested.addPass(createLoopInvariantCodeMotionPass());
70	
71	      if (opts.optLevel >= 3) {
72	        // 3) loop split, followed by another canonicalization sweep.
73	        nested.addPass(createLoopSplitPass({opts.loopSplitThreshold}));
74	        nested.addPass(createCanonicalizerPass());
75	      }
76	    }
77	  }
78	  return success();
79	}
80	
81	/// Build optimization pipeline (default or with builder/text overrides)
82	static LogicalResult
83	buildCudaTileOptimizationPipeline(PassManager &pm,
84	                                  const TileIROptimizerOptions &opts) {
85	  // Pipeline is nested under cuda_tile::EntryOp.
86	  auto &nested = pm.nestAny();
87	
88	  // Add additional passes before default pipeline
89	  if (failed(parseTextInto(opts.pipelinePreText, nested, pm.getContext())))
90	    return failure();
91	
92	  // Add default pipeline
93	  if (failed(buildDefaultCudaTilePipeline(nested, opts)))
94	    return failure();
95	
96	  // Add additional passes after default pipeline
97	  return parseTextInto(opts.pipelinePostText, nested, pm.getContext());
98	}
99	
100	//===----------------------------------------------------------------------===//
101	// CUDA Tile IR parsing
102	//===----------------------------------------------------------------------===//
103	
104	/// Parses the given bytecode buffer into a CUDA Tile IR module. Returns null if
105	/// the buffer is not valid bytecode.
106	OwningOpRef<mlir::ModuleOp> parseTileIRBytecode(llvm::MemoryBufferRef bytecode,
107	                                                MLIRContext &context) {
108	  // Check if this is CUDA Tile IR bytecode.
109	  if (!isTileIRBytecode(bytecode))
110	    return {};
111	  context.loadDialect<cuda_tile::CudaTileDialect>();
112	
113	  OwningOpRef<cuda_tile::ModuleOp> tileIRModule =
114	      cuda_tile::readBytecode(bytecode, context);
115	  if (!tileIRModule)
116	    return {};
117	
118	  // Wrap the bytecode module into a builtin module.
119	  OwningOpRef<mlir::ModuleOp> module =
120	      mlir::ModuleOp::create(UnknownLoc::get(&context));
121	  module->getBody()->push_back(tileIRModule.release());
122	  return module;
123	}
124	
125	// -----------------------------------------------------------------------------
126	// Small helpers
127	// -----------------------------------------------------------------------------
128	
129	// write Bytecode to buffer
130	static LogicalResult writeBytecodeToBuffer(cuda_tile::ModuleOp module,
131	                                           std::string &out) {
132	  out.clear();
133	  llvm::raw_string_ostream os(out);
134	  if (failed(cuda_tile::writeBytecode(os, module,
135	                                      BytecodeVersion::kCurrentVersion)))
136	    return failure();
137	  os.flush();
138	  return success();
139	}
140	
141	// Utility: emit error and return failure().
142	static LogicalResult emitConfigError(MLIRContext *context, const char *msg) {
143	  return emitError(UnknownLoc::get(context)) << msg;
144	}
145	static LogicalResult emitConfigError(MLIRContext *context, std::string msg) {
146	  return emitError(UnknownLoc::get(context)) << msg;
147	}
148	
149	// Validate provided configuration
150	static LogicalResult validateConfig(TileIROptimizerConfig &cfg,
151	                                    MLIRContext *context) {
152	  using O = TileIROptOutputMode;
153	  if ((cfg.output.mode & O::BytecodeFile) != O::None &&
154	      cfg.output.bytecodeFile.empty())
155	    return emitConfigError(
156	        context, "BytecodeFile requested but bytecodeOutputFile is empty");
157	  if ((cfg.output.mode & O::BytecodeMemory) != O::None &&
158	      !cfg.output.bytecodeBuffer)
159	    return emitConfigError(
160	        context, "BytecodeMemory requested but bytecodeOutputBuffer==nullptr");
161	  if ((cfg.output.mode & O::MlirFile) != O::None && cfg.output.mlirFile.empty())
162	    return emitConfigError(context,
163	                           "MlirFile requested but mlirOutputFile is empty");
164	  // Input Buffer case
165	  if (auto buf = std::get_if<TileIROptInput::BufferT>(&cfg.input.value))
166	    if (buf->empty())
167	      return emitConfigError(context, "loadInputModule: input buffer is empty");
168	  // Input File case
169	  if (auto fname = std::get_if<TileIROptInput::FileT>(&cfg.input.value))
170	    if (fname->empty())
171	      return emitConfigError(context, "loadInputModule: filename is empty");
172	
173	  return success();
174	}
175	
176	// Loads/produces a ModuleOp into `outMod` based on cfg.input.kind.
177	// Returns success() on success, failure() on any error.
178	static LogicalResult loadInputModule(TileIROptimizerConfig &cfg,
179	                                     MLIRContext &context,
180	                                     OwningOpRef<mlir::ModuleOp> &outMod) {
181	  // The values of cfg.input.buffer & cfg.input.filename are already checked
182	  // during the call of validateConfig()
183	  // 1) Materialize a MemoryBuffer + MemoryBufferRef regardless of source
184	  std::unique_ptr<llvm::MemoryBuffer> owned;
185	  llvm::MemoryBufferRef ref;
186	  StringRef *buf = nullptr;
187	
188	  if (auto fname = std::get_if<TileIROptInput::FileT>(&cfg.input.value)) {
189	    // Read raw bytes (no text-mode CRLF translation), so detection is reliable.
190	    auto bufOrErr = llvm::MemoryBuffer::getFile(*fname, /*IsText=*/false);
191	    if (!bufOrErr)
192	      return emitConfigError(
193	          &context, (llvm::Twine("Failed to read file: ") + *fname).str());
194	
195	    owned = std::move(*bufOrErr);
196	    ref = owned->getMemBufferRef();
197	  } else {
198	    buf = std::get_if<TileIROptInput::BufferT>(&cfg.input.value);
199	    // No copy here. Build a non-owning view onto caller's memory.
200	    ref = llvm::MemoryBufferRef(*buf, "");
201	  }
202	
203	  // Parse depending on detected type
204	  if (cuda_tile::isTileIRBytecode(ref)) {
205	    // CUDA Tile IR bytecode
206	    outMod = parseTileIRBytecode(ref, context);
207	  } else {
208	    // MLIR textual IR
209	    llvm::SourceMgr sm;
210	    if (buf) {
211	      // Create an owned, null-terminated copy ONLY for the Buffer path.
212	      // This guarantees ownership + '\0' for SourceMgr.
213	      owned = llvm::MemoryBuffer::getMemBufferCopy(*buf, "");
214	      if (!owned)
215	        return emitConfigError(&context,
216	                               "Failed to allocate buffer copy for MLIR text.");
217	    }
218	    // If cfg.input.kind == K::File, 'owned' was already set from getFile()
219	    // above.
220	    sm.AddNewSourceBuffer(std::move(owned), llvm::SMLoc());
221	    outMod = parseSourceFile<mlir::ModuleOp>(sm, &context);
222	  }
223	
224	  if (!outMod)
225	    return emitConfigError(&context, "Failed to parse input");
226	  return success();
227	}
