229	static LogicalResult emitOutputs(TileIROptimizerConfig &cfg,
230	                                 OwningOpRef<mlir::ModuleOp> &parentModule) {
231	  using O = TileIROptOutputMode;
232	  MLIRContext *context = parentModule->getContext();
233	
234	  // 1) Bytecode: file / memory
235	  if ((cfg.output.mode & (O::BytecodeFile | O::BytecodeMemory)) != O::None) {
236	    // → Generate bytecode once to memory, then branch.
237	    std::string bc;
238	    if (failed(
239	            writeBytecodeToBuffer(extractCudaTileModuleOp(*parentModule), bc)))
240	      return emitConfigError(context, "Bytecode generation failed");
241	
242	    if ((cfg.output.mode & O::BytecodeFile) != O::None) {
243	      std::string err;
244	      if (auto of = openOutputFile(cfg.output.bytecodeFile, &err)) {
245	        of->os().write(bc.data(), bc.size());
246	        of->keep();
247	      } else {
248	        return emitConfigError(context, err);
249	      }
250	    }
251	    if ((cfg.output.mode & O::BytecodeMemory) != O::None)
252	      *cfg.output.bytecodeBuffer = std::move(bc);
253	  }
254	
255	  // 2) MLIR textual: file / screen
256	  if ((cfg.output.mode & (O::MlirFile | O::MlirStdout)) != O::None) {
257	    // Print once to a string and reuse for file / screen.
258	    std::string mlirText;
259	    {
260	      llvm::raw_string_ostream os(mlirText);
261	      // Optional: pass OpPrintingFlags if you want elideAttrs(), etc.
262	      parentModule->print(os);
