265	    if ((cfg.output.mode & O::MlirFile) != O::None) {
266	      std::string err;
267	      if (auto of = openOutputFile(cfg.output.mlirFile, &err)) {
268	        of->os() << mlirText;
269	        of->keep();
270	      } else {
271	        return emitConfigError(context, err);
272	      }
273	    }
274	
275	    if ((cfg.output.mode & O::MlirStdout) != O::None)
276	      (cfg.output.screenOS ? *cfg.output.screenOS : llvm::outs())
277	          << mlirText << '\n';
278	  }
279	
280	  return success();
281	}
